class Solution:
    def watchedVideosByFriends(self, watchedVideos, friends, id, level):
        """
        :type watchedVideos: List[List[str]]
        :type friends: List[List[int]]
        :type id: int
        :type level: int
        :rtype: List[str]
        """
        # BFS to find friends at specific level
        from collections import deque, defaultdict

        queue = deque([(id, 0)])
        visited = {id}
        current_level_friends = []

        while queue:
            person, dist = queue.popleft()

            if dist == level:
                current_level_friends.append(person)
                continue

            if dist < level:
                for friend in friends[person]:
                    if friend not in visited:
                        visited.add(friend)
                        queue.append((friend, dist + 1))

        # Count videos watched by level friends
        video_count = defaultdict(int)
        for person in current_level_friends:
            for video in watchedVideos[person]:
                video_count[video] += 1

        # Sort by frequency then alphabetically
        result = sorted(video_count.items(), key=lambda x: (x[1], x[0]))
        return [v for v, c in result]
